module Comparator8bit (
	input [7:0] a,
	input [7:0] b,
	output reg le,
	output reg eq,
	output reg lt
);
    always @(*) begin
        if (a > b) begin
            le = 1;
            eq = 0;
            lt = 0;
        end else if (a == b) begin
            le = 0;
            eq = 1;
            lt = 0;
        end else begin
            le = 0;
            eq = 0;
            lt = 1;
        end
    end
endmodule
